mapper.update:
UPDATE jsh_customer_statement
SET status=#{status}, sign_status=#{signStatus}, attachment=#{attachment},
    remark=#{remark}, total_weight=#{totalWeight}, total_amount=#{totalAmount},
    delete_flag=#{deleteFlag}
WHERE id=#{id}

mapper.sql:
FROM jsh_depot_item di
JOIN jsh_depot_head dh ON dh.id = di.header_id AND ifnull(dh.delete_flag,'0') != '1'
JOIN jsh_material m    ON m.id  = di.material_id
LEFT JOIN jsh_material_category mc ON mc.id = m.category_id
LEFT JOIN jsh_supplier s           ON s.id  = dh.organ_id
WHERE dh.type = '出库' AND dh.sub_type = '销售'
  AND ifnull(di.delete_flag,'0') != '1'
  AND dh.tenant_id = #{tenantId}

    AND dh.organ_id = #{organId}


    AND dh.oper_time >= #{beginTime}


    AND dh.oper_time <= #{endTime}

  AND di.id NOT IN (
    SELECT csi.depot_item_id
    FROM jsh_customer_statement_item csi
    JOIN jsh_customer_statement cs ON cs.id = csi.statement_id
    WHERE ifnull(cs.delete_flag,'0') != '1'
      AND ifnull(csi.delete_flag,'0') != '1'
      AND cs.tenant_id = #{tenantId}
  )

mapper.select:
SELECT di.id, dh.id as depotHeadId, dh.number as billNo, dh.oper_time as billTime, dh.remark as billRemark, mc.name as categoryName, m.name as brand, m.model, m.standard, m.weight as unitWeight, di.oper_number as operNumber, di.weight as itemWeight, di.unit_price as unitPrice, di.all_price as allPrice, s.supplier as customerName
ORDER BY dh.oper_time, di.id
LIMIT #{offset}, #{rows}

SELECT cs.id, cs.statement_no as statementNo,
       s.supplier as customerName,
       DATE_FORMAT(cs.begin_time,'%Y-%m-%d') as beginTimeStr,
       DATE_FORMAT(cs.end_time,'%Y-%m-%d') as endTimeStr,
       cs.total_weight as totalWeight,
       cs.total_amount as totalAmount,
       cs.status, cs.sign_status as signStatus,
       cs.attachment, cs.remark,
       DATE_FORMAT(cs.create_time,'%Y-%m-%d %H:%i:%s') as createTimeStr
FROM jsh_customer_statement cs
LEFT JOIN jsh_supplier s ON s.id = cs.organ_id
WHERE ifnull(cs.delete_flag,'0') != '1'
  AND cs.tenant_id = #{tenantId}

    AND cs.organ_id = #{organId}


    AND cs.status = #{status}


    AND cs.sign_status = #{signStatus}


    AND cs.begin_time >= #{beginTime}


    AND cs.end_time <= #{endTime}

ORDER BY cs.create_time DESC

  LIMIT #{offset}, #{rows}

SELECT count(1)
FROM jsh_customer_statement cs
WHERE ifnull(cs.delete_flag,'0') != '1'
  AND cs.tenant_id = #{tenantId}

    AND cs.organ_id = #{organId}


    AND cs.status = #{status}


    AND cs.sign_status = #{signStatus}


    AND cs.begin_time >= #{beginTime}


    AND cs.end_time <= #{endTime}

